    // TODO 1 (your coding task): matching / execution.
    // A marketable order arrives on `aggressorSide` and consumes `size` from the BEST
    // prices of the opposite book, honouring price-time priority (FIFO within a level).
    // Walk side(-aggressorSide) from its first entry, take from the head order of each
    // level, reduce or remove filled orders, drop emptied price levels, and remember to
    // remove fully-filled orders from byId. Stop when `size` is exhausted or the book
    // is empty. Write this yourself; this is part of the assessed coding.
    // ====================================================================
    void execute(int aggressorSide, int size){
        // Opposite book to the aggressor
        TreeMap<Long, ArrayDeque<Order>> book = side(-aggressorSide);

        // Sweep the book from the best price while we still have quantity to fill
        while (size > 0) {
            Map.Entry<Long, ArrayDeque<Order>> level = book.firstEntry();
            if (level == null) break; // book exhausted

            ArrayDeque<Order> queue = level.getValue();
            // Consume orders in FIFO order at this price level
            while (size > 0 && !queue.isEmpty()) {
                Order resting = queue.peekFirst();
                if (resting == null) break;

                int take = Math.min(size, resting.size);
                resting.size -= take;
                size -= take;

                if (resting.size == 0) {
                    // fully filled: remove from the queue and from id map
                    queue.removeFirst();
                    byId.remove(resting.id);
                }
            }

            // If this price level is empty, remove it from the map and continue to next best
            if (queue.isEmpty()) book.remove(level.getKey());
        }
    }

